import { useState, useCallback } from 'react';
import { useDropzone } from 'react-dropzone';
import * as XLSX from 'xlsx';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Checkbox } from '@/components/ui/checkbox';
import { Upload, FileSpreadsheet, AlertTriangle, CheckCircle, X } from 'lucide-react';
import { type Lead } from '@/lib/types';

interface ImportedLead {
  firstName: string;
  lastName: string;
  email: string;
  phone: string;
  source: string;
  notes?: string;
}

interface ConflictItem {
  imported: ImportedLead;
  existing: Lead;
  action: 'skip' | 'overwrite';
}

interface ExcelImportProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  existingLeads: Lead[];
  onImport: (leads: ImportedLead[], conflicts: ConflictItem[]) => void;
}

export function ExcelImport({ open, onOpenChange, existingLeads, onImport }: ExcelImportProps) {
  const [step, setStep] = useState<'upload' | 'review' | 'conflicts'>('upload');
  const [importedData, setImportedData] = useState<ImportedLead[]>([]);
  const [conflicts, setConflicts] = useState<ConflictItem[]>([]);
  const [cleanData, setCleanData] = useState<ImportedLead[]>([]);
  const [fileName, setFileName] = useState('');

  const findConflicts = (data: ImportedLead[]): { clean: ImportedLead[]; conflicts: ConflictItem[] } => {
    const conflictItems: ConflictItem[] = [];
    const cleanItems: ImportedLead[] = [];

    data.forEach((item) => {
      const existing = existingLeads.find(
        (lead) => lead.email === item.email || lead.phone === item.phone
      );

      if (existing) {
        conflictItems.push({
          imported: item,
          existing,
          action: 'skip',
        });
      } else {
        cleanItems.push(item);
      }
    });

    return { clean: cleanItems, conflicts: conflictItems };
  };

  const onDrop = useCallback((acceptedFiles: File[]) => {
    const file = acceptedFiles[0];
    if (!file) return;

    setFileName(file.name);
    const reader = new FileReader();

    reader.onload = (e) => {
      const data = e.target?.result;
      const workbook = XLSX.read(data, { type: 'binary' });
      const sheetName = workbook.SheetNames[0];
      const sheet = workbook.Sheets[sheetName];
      const jsonData = XLSX.utils.sheet_to_json<ImportedLead>(sheet);

      const normalizedData: ImportedLead[] = jsonData.map((row: any) => {
        const fullName = row['Imię nazwisko'] || row['Imie nazwisko'] || '';
        let firstName = row.firstName || row['First Name'] || row.first_name || '';
        let lastName = row.lastName || row['Last Name'] || row.last_name || '';

        if (fullName && (!firstName || !lastName)) {
          const nameParts = fullName.trim().split(' ').filter(Boolean);
          if (nameParts.length >= 2) {
            lastName = nameParts.pop() || '';
            firstName = nameParts.join(' ');
          } else if (nameParts.length === 1) {
            firstName = nameParts[0];
            lastName = '-';
          }
        }

        if (!firstName) firstName = '-';
        if (!lastName) lastName = '-';

        return {
          firstName: firstName.trim(),
          lastName: lastName.trim(),
          email: row['e-mail'] || row['E-mail'] || row.email || row.Email || '',
          phone: String(row['Telefon'] || row.phone || row.Phone || row.telephone || '').trim(),
          source: row['Źródło'] || row['Zrodlo'] || row.source || row.Source || 'Excel Import',
          notes: row['Notatki'] || row['notatki'] || row['Uwagi'] || row['uwagi'] || row['Komentarz'] || row['komentarz'] || row.notes || row.Notes || '',
        };
      }).filter(lead => lead.email || lead.phone);

      setImportedData(normalizedData);
      const { clean, conflicts: foundConflicts } = findConflicts(normalizedData);
      setCleanData(clean);
      setConflicts(foundConflicts);
      setStep('review');
    };

    reader.readAsBinaryString(file);
  }, [existingLeads]);

  const { getRootProps, getInputProps, isDragActive } = useDropzone({
    onDrop,
    accept: {
      'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet': ['.xlsx'],
      'application/vnd.ms-excel': ['.xls'],
    },
    multiple: false,
  });

  const handleConflictAction = (index: number, action: 'skip' | 'overwrite') => {
    setConflicts((prev) =>
      prev.map((c, i) => (i === index ? { ...c, action } : c))
    );
  };

  const handleSelectAllConflicts = (action: 'skip' | 'overwrite') => {
    setConflicts((prev) => prev.map((c) => ({ ...c, action })));
  };

  const handleImport = () => {
    onImport(cleanData, conflicts);
    handleClose();
  };

  const handleClose = () => {
    setStep('upload');
    setImportedData([]);
    setConflicts([]);
    setCleanData([]);
    setFileName('');
    onOpenChange(false);
  };

  return (
    <Dialog open={open} onOpenChange={handleClose}>
      <DialogContent className="max-w-2xl max-h-[85vh] flex flex-col">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <FileSpreadsheet className="w-5 h-5 text-primary" />
            Import Leads from Excel
          </DialogTitle>
        </DialogHeader>

        {step === 'upload' && (
          <div
            {...getRootProps()}
            className={`mt-4 p-12 border-2 border-dashed rounded-lg text-center cursor-pointer transition-colors ${
              isDragActive ? 'border-primary bg-primary/5' : 'border-border hover:border-primary/50'
            }`}
            data-testid="dropzone-excel"
          >
            <input {...getInputProps()} />
            <Upload className="w-12 h-12 mx-auto mb-4 text-muted-foreground" />
            <p className="text-sm font-medium mb-1">
              {isDragActive ? 'Drop your file here' : 'Drag & drop an Excel file here'}
            </p>
            <p className="text-xs text-muted-foreground">
              or click to browse (.xlsx, .xls)
            </p>
          </div>
        )}

        {step === 'review' && (
          <div className="mt-4 space-y-4 flex-1 overflow-hidden flex flex-col">
            <div className="flex items-center gap-3 p-3 rounded-lg bg-muted">
              <FileSpreadsheet className="w-5 h-5 text-primary" />
              <span className="text-sm font-medium flex-1">{fileName}</span>
              <Badge variant="secondary">{importedData.length} rows</Badge>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="p-4 rounded-lg bg-green-50 dark:bg-green-900/20 border border-green-200 dark:border-green-800">
                <div className="flex items-center gap-2 mb-1">
                  <CheckCircle className="w-4 h-4 text-green-600 dark:text-green-400" />
                  <span className="font-medium text-green-700 dark:text-green-300">Ready to import</span>
                </div>
                <p className="text-2xl font-bold text-green-700 dark:text-green-300">{cleanData.length}</p>
              </div>
              <div className="p-4 rounded-lg bg-amber-50 dark:bg-amber-900/20 border border-amber-200 dark:border-amber-800">
                <div className="flex items-center gap-2 mb-1">
                  <AlertTriangle className="w-4 h-4 text-amber-600 dark:text-amber-400" />
                  <span className="font-medium text-amber-700 dark:text-amber-300">Conflicts found</span>
                </div>
                <p className="text-2xl font-bold text-amber-700 dark:text-amber-300">{conflicts.length}</p>
              </div>
            </div>

            {conflicts.length > 0 && (
              <>
                <div className="flex items-center justify-between gap-2">
                  <p className="text-sm text-muted-foreground">
                    Resolve conflicts before importing
                  </p>
                  <div className="flex items-center gap-2">
                    <Button 
                      variant="outline" 
                      size="sm" 
                      onClick={() => handleSelectAllConflicts('skip')}
                      data-testid="button-skip-all"
                    >
                      Skip All
                    </Button>
                    <Button 
                      variant="outline" 
                      size="sm" 
                      onClick={() => handleSelectAllConflicts('overwrite')}
                      data-testid="button-overwrite-all"
                    >
                      Overwrite All
                    </Button>
                  </div>
                </div>

                <ScrollArea className="flex-1 border rounded-lg">
                  <div className="divide-y">
                    {conflicts.map((conflict, index) => (
                      <div key={index} className="p-4" data-testid={`conflict-item-${index}`}>
                        <div className="flex items-start justify-between gap-4">
                          <div className="flex-1 min-w-0">
                            <p className="font-medium text-sm">
                              {conflict.imported.firstName} {conflict.imported.lastName}
                            </p>
                            <p className="text-xs text-muted-foreground truncate">
                              {conflict.imported.email} | {conflict.imported.phone}
                            </p>
                            <p className="text-xs text-amber-600 dark:text-amber-400 mt-1">
                              Matches: {conflict.existing.firstName} {conflict.existing.lastName}
                            </p>
                          </div>
                          <div className="flex items-center gap-2">
                            <Button
                              variant={conflict.action === 'skip' ? 'secondary' : 'ghost'}
                              size="sm"
                              onClick={() => handleConflictAction(index, 'skip')}
                              data-testid={`button-skip-${index}`}
                            >
                              Skip
                            </Button>
                            <Button
                              variant={conflict.action === 'overwrite' ? 'secondary' : 'ghost'}
                              size="sm"
                              onClick={() => handleConflictAction(index, 'overwrite')}
                              data-testid={`button-overwrite-${index}`}
                            >
                              Overwrite
                            </Button>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                </ScrollArea>
              </>
            )}
          </div>
        )}

        <DialogFooter className="mt-4 gap-2">
          <Button variant="outline" onClick={handleClose} data-testid="button-cancel-import">
            Cancel
          </Button>
          {step === 'review' && (
            <Button onClick={handleImport} data-testid="button-confirm-import">
              Import {cleanData.length + conflicts.filter(c => c.action === 'overwrite').length} Leads
            </Button>
          )}
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

