import { useState } from 'react';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Calendar, Clock, ChevronUp, ChevronDown } from 'lucide-react';
import { format } from 'date-fns';

interface TimePickerModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  date: Date;
  leadName: string;
  onConfirm: (dateWithTime: Date) => void;
}

export function TimePickerModal({ 
  open, 
  onOpenChange, 
  date, 
  leadName, 
  onConfirm 
}: TimePickerModalProps) {
  const [hours, setHours] = useState(9);
  const [minutes, setMinutes] = useState(0);

  const incrementHours = () => setHours((h) => (h + 1) % 24);
  const decrementHours = () => setHours((h) => (h - 1 + 24) % 24);
  const incrementMinutes = () => setMinutes((m) => (m + 15) % 60);
  const decrementMinutes = () => setMinutes((m) => (m - 15 + 60) % 60);

  const handleConfirm = () => {
    const newDate = new Date(date);
    newDate.setHours(hours, minutes, 0, 0);
    onConfirm(newDate);
    onOpenChange(false);
  };

  const handleCancel = () => {
    onOpenChange(false);
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-md">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <Clock className="w-5 h-5 text-primary" />
            Set Contact Time
          </DialogTitle>
        </DialogHeader>

        <div className="py-4 space-y-6">
          <div className="p-4 rounded-lg bg-muted text-center">
            <div className="flex items-center justify-center gap-2 text-sm text-muted-foreground mb-1">
              <Calendar className="w-4 h-4" />
              <span>Scheduling contact for</span>
            </div>
            <p className="font-semibold text-lg">{leadName}</p>
            <p className="text-sm font-mono mt-1">{format(date, 'EEEE, MMMM d, yyyy')}</p>
          </div>

          <div className="space-y-2">
            <Label className="text-center block">Select Time</Label>
            <div className="flex items-center justify-center gap-4">
              <div className="flex flex-col items-center">
                <Button 
                  variant="ghost" 
                  size="icon" 
                  onClick={incrementHours}
                  data-testid="button-increment-hours"
                >
                  <ChevronUp className="w-5 h-5" />
                </Button>
                <Input
                  type="text"
                  value={hours.toString().padStart(2, '0')}
                  readOnly
                  className="w-16 text-center font-mono text-2xl font-bold h-14"
                  data-testid="input-hours"
                />
                <Button 
                  variant="ghost" 
                  size="icon" 
                  onClick={decrementHours}
                  data-testid="button-decrement-hours"
                >
                  <ChevronDown className="w-5 h-5" />
                </Button>
              </div>
              <span className="text-3xl font-bold">:</span>
              <div className="flex flex-col items-center">
                <Button 
                  variant="ghost" 
                  size="icon" 
                  onClick={incrementMinutes}
                  data-testid="button-increment-minutes"
                >
                  <ChevronUp className="w-5 h-5" />
                </Button>
                <Input
                  type="text"
                  value={minutes.toString().padStart(2, '0')}
                  readOnly
                  className="w-16 text-center font-mono text-2xl font-bold h-14"
                  data-testid="input-minutes"
                />
                <Button 
                  variant="ghost" 
                  size="icon" 
                  onClick={decrementMinutes}
                  data-testid="button-decrement-minutes"
                >
                  <ChevronDown className="w-5 h-5" />
                </Button>
              </div>
            </div>
          </div>
        </div>

        <DialogFooter className="gap-2">
          <Button variant="outline" onClick={handleCancel} data-testid="button-cancel-time">
            Cancel
          </Button>
          <Button onClick={handleConfirm} data-testid="button-confirm-time">
            Confirm
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

client/src/components/LeadDetailModal.ts.content:
import { useState } from 'react';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from '@/components/ui/collapsible';
import { Avatar, AvatarFallback } from '@/components/ui/avatar';
import { StatusBadge } from './StatusBadge';
import { Phone, Mail, Building, Calendar, User, Clock, Edit2, Save, X, Loader2, ChevronDown, ChevronUp, FileText } from 'lucide-react';
import { type Lead, type LeadHistoryItem, type LeadStatus, type User as UserType } from '@/lib/types';
import { format, parseISO, isValid } from 'date-fns';

function formatContactDateForInput(contactDate: Date | string | null | undefined): string {
  if (!contactDate) return '';
  try {
    const date = typeof contactDate === 'string' ? parseISO(contactDate) : new Date(contactDate);
    if (!isValid(date)) return '';
    return format(date, "yyyy-MM-dd'T'HH:mm");
  } catch {
    return '';
  }
}

interface LeadDetailModalProps {
  lead: Lead | null;
  history: LeadHistoryItem[];
  users: UserType[];
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onSave: (lead: Lead) => Promise<void>;
  isSaving?: boolean;
}

const STATUSES: LeadStatus[] = ['Nowy', 'W_toku', 'Wstrzymany', 'Wniosek', 'Sukces', 'Porazka'];

export function LeadDetailModal({ 
  lead, 
  history, 
  users,
  open, 
  onOpenChange, 
  onSave,
  isSaving = false,
}: LeadDetailModalProps) {
  const [isEditing, setIsEditing] = useState(false);
  const [editedLead, setEditedLead] = useState<Lead | null>(null);
  const [historyOpen, setHistoryOpen] = useState(false);

  if (!lead) return null;

  const currentLead = isEditing && editedLead ? editedLead : lead;
  const initials = `${currentLead.firstName[0]}${currentLead.lastName[0]}`.toUpperCase();

  const handleEdit = () => {
    setEditedLead({ ...lead });
    setIsEditing(true);
  };

  const handleCancel = () => {
    setEditedLead(null);
    setIsEditing(false);
  };

  const handleSave = async () => {
    if (editedLead) {
      try {
        await onSave(editedLead);
        setIsEditing(false);
        setEditedLead(null);
      } catch {
        // Error handled by parent, keep editing state
      }
    }
  };

  const updateField = <K extends keyof Lead>(field: K, value: Lead[K]) => {
    if (editedLead) {
      setEditedLead({ ...editedLead, [field]: value });
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-3xl max-h-[90vh] overflow-hidden flex flex-col">
        <DialogHeader className="flex-shrink-0">
          <div className="flex items-center justify-between gap-4">
            <div className="flex items-center gap-4">
              <Avatar className="h-12 w-12">
                <AvatarFallback className="text-lg font-medium bg-primary/10 text-primary">
                  {initials}
                </AvatarFallback>
              </Avatar>
              <div>
                <DialogTitle className="text-xl font-semibold">
                  {currentLead.firstName} {currentLead.lastName}
                </DialogTitle>
                <div className="flex items-center gap-2 mt-1">
                  <StatusBadge status={currentLead.status} />
                  <span className="text-sm text-muted-foreground">{currentLead.source}</span>
                </div>
              </div>
            </div>
            <div className="flex items-center gap-2">
              {isEditing ? (
                <>
                  <Button variant="ghost" size="sm" onClick={handleCancel} data-testid="button-cancel-edit">
                    <X className="w-4 h-4 mr-1" /> Anuluj
                  </Button>
                  <Button size="sm" onClick={handleSave} disabled={isSaving} data-testid="button-save-lead">
                    {isSaving ? <Loader2 className="w-4 h-4 mr-1 animate-spin" /> : <Save className="w-4 h-4 mr-1" />}
                    Zapisz
                  </Button>
                </>
              ) : (
                <Button variant="outline" size="sm" onClick={handleEdit} data-testid="button-edit-lead">
                  <Edit2 className="w-4 h-4 mr-1" /> Edytuj
                </Button>
              )}
            </div>
          </div>
        </DialogHeader>

        <div className="flex-1 overflow-y-auto mt-6 space-y-6">
          <div className="space-y-4">
            <h3 className="text-sm font-semibold uppercase tracking-wide text-muted-foreground">
              Dane kontaktowe
            </h3>

            <div className="space-y-4">
              {isEditing ? (
                <>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <Label htmlFor="firstName">Imie</Label>
                      <Input
                        id="firstName"
                        value={editedLead?.firstName || ''}
                        onChange={(e) => updateField('firstName', e.target.value)}
                        data-testid="input-first-name"
                      />
                    </div>
                    <div className="space-y-2">
                      <Label htmlFor="lastName">Nazwisko</Label>
                      <Input
                        id="lastName"
                        value={editedLead?.lastName || ''}
                        onChange={(e) => updateField('lastName', e.target.value)}
                        data-testid="input-last-name"
                      />
                    </div>
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="email">Email</Label>
                    <Input
                      id="email"
                      type="email"
                      value={editedLead?.email || ''}
                      onChange={(e) => updateField('email', e.target.value)}
                      data-testid="input-email"
                    />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="phone">Telefon</Label>
                    <Input
                      id="phone"
                      value={editedLead?.phone || ''}
                      onChange={(e) => updateField('phone', e.target.value)}
                      data-testid="input-phone"
                    />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="source">Zrodlo</Label>
                    <Input
                      id="source"
                      value={editedLead?.source || ''}
                      onChange={(e) => updateField('source', e.target.value)}
                      data-testid="input-source"
                    />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="status">Status</Label>
                    <Select
                      value={editedLead?.status}
                      onValueChange={(value) => updateField('status', value as LeadStatus)}
                    >
                      <SelectTrigger data-testid="select-status">
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        {STATUSES.map((status) => (
                          <SelectItem key={status} value={status}>
                            {status.replace('_', ' ')}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="assignedTo">Przypisany do</Label>
                    <Select
                      value={editedLead?.assignedToId || ''}
                      onValueChange={(value) => updateField('assignedToId', value)}
                    >
                      <SelectTrigger data-testid="select-assigned-to">
                        <SelectValue placeholder="Wybierz uzytkownika" />
                      </SelectTrigger>
                      <SelectContent>
                        {users.map((user) => (
                          <SelectItem key={user.id} value={user.id}>
                            {user.name}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="contactDate">Data kontaktu</Label>
                    <div className="flex items-center gap-2">
                      <Input
                        id="contactDate"
                        type="datetime-local"
                        value={formatContactDateForInput(editedLead?.contactDate)}
                        onChange={(e) => {
                          const value = e.target.value;
                          updateField('contactDate', value ? new Date(value) : null);
                        }}
                        className="flex-1"
                        data-testid="input-contact-date"
                      />
                      {editedLead?.contactDate && (
                        <Button
                          type="button"
                          variant="ghost"
                          size="icon"
                          onClick={() => updateField('contactDate', null)}
                          data-testid="button-clear-contact-date"
                        >
                          <X className="w-4 h-4" />
                        </Button>
                      )}
                    </div>
                    <p className="text-xs text-muted-foreground">
                      Ustaw date i godzine kontaktu - lead pojawi sie w kalendarzu
                    </p>
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="notes">Notatki</Label>
                    <Textarea
                      id="notes"
                      value={editedLead?.notes || ''}
                      onChange={(e) => updateField('notes', e.target.value)}
                      rows={4}
                      data-testid="textarea-notes"
                    />
                  </div>
                </>
              ) : (
                <div className="grid grid-cols-2 gap-4">
                  <div className="flex items-center gap-3 text-sm">
                    <Mail className="w-4 h-4 text-muted-foreground shrink-0" />
                    <a href={`mailto:${currentLead.email}`} className="text-primary hover:underline">
                      {currentLead.email}
                    </a>
                  </div>
                  <div className="flex items-center gap-3 text-sm">
                    <Phone className="w-4 h-4 text-muted-foreground shrink-0" />
                    <span className="font-mono">{currentLead.phone}</span>
                  </div>
                  <div className="flex items-center gap-3 text-sm">
                    <Building className="w-4 h-4 text-muted-foreground shrink-0" />
                    <span>{currentLead.source}</span>
                  </div>
                  {currentLead.contactDate && (
                    <div className="flex items-center gap-3 text-sm">
                      <Calendar className="w-4 h-4 text-muted-foreground shrink-0" />
                      <span className="font-mono">
                        {format(currentLead.contactDate, 'MMM d, yyyy HH:mm')}
                      </span>
                    </div>
                  )}
                  {currentLead.assignedTo && (
                    <div className="flex items-center gap-3 text-sm">
                      <User className="w-4 h-4 text-muted-foreground shrink-0" />
                      <span>Przypisany do: {currentLead.assignedTo.name}</span>
                    </div>
                  )}
                </div>
              )}
            </div>
          </div>

          {!isEditing && (
            <div className="space-y-3">
              <h3 className="text-sm font-semibold uppercase tracking-wide text-muted-foreground flex items-center gap-2">
                <FileText className="w-4 h-4" />
                Notatki
              </h3>
              {currentLead.notes ? (
                <div className="p-4 rounded-lg bg-muted/50 border">
                  <p className="text-sm whitespace-pre-wrap">{currentLead.notes}</p>
                </div>
              ) : (
                <div className="p-4 rounded-lg bg-muted/30 text-center">
                  <p className="text-sm text-muted-foreground">Brak notatek</p>
                </div>
              )}
            </div>
          )}

          <Collapsible open={historyOpen} onOpenChange={setHistoryOpen}>
            <CollapsibleTrigger asChild>
              <Button 
                variant="outline" 
                className="w-full justify-between"
                data-testid="button-toggle-history"
              >
                <span className="flex items-center gap-2">
                  <Clock className="w-4 h-4" />
                  Historia aktywnosci ({history.length})
                </span>
                {historyOpen ? <ChevronUp className="w-4 h-4" /> : <ChevronDown className="w-4 h-4" />}
              </Button>
            </CollapsibleTrigger>
            <CollapsibleContent className="mt-4">
              {history.length === 0 ? (
                <div className="py-6 text-center text-muted-foreground">
                  <p className="text-sm">Brak aktywnosci</p>
                </div>
              ) : (
                <div className="relative">
                  <div className="absolute left-3 top-0 bottom-0 w-0.5 bg-border" />
                  <div className="space-y-3">
                    {history.map((item, index) => (
                      <div 
                        key={item.id} 
                        className={`relative pl-8 ${index % 2 === 0 ? 'bg-muted/30' : ''} py-3 pr-3 rounded-r-lg`}
                      >
                        <div className="absolute left-1.5 top-4 w-3 h-3 rounded-full bg-primary border-2 border-background" />
                        <div className="flex items-start justify-between gap-2">
                          <div>
                            <p className="text-sm font-medium">{item.userName}</p>
                            <p className="text-sm text-muted-foreground">{item.action}</p>
                          </div>
                          <span className="text-xs text-muted-foreground font-mono shrink-0">
                            {format(item.timestamp, 'MMM d, HH:mm')}
                          </span>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </CollapsibleContent>
          </Collapsible>
        </div>
      </DialogContent>
    </Dialog>
  );
}

client/src/hooks/use-mobile.tsx.content:
import * as React from "react"

const MOBILE_BREAKPOINT = 768

export function useIsMobile() {
  const [isMobile, setIsMobile] = React.useState<boolean | undefined>(undefined)

  React.useEffect(() => {
    const mql = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT - 1}px)`)
    const onChange = () => {
      setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)
    }
    mql.addEventListener("change", onChange)
    setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)
    return () => mql.removeEventListener("change", onChange)
  }, [])

  return !!isMobile
}

