import { useState } from 'react';
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Switch } from '@/components/ui/switch';
import { Label } from '@/components/ui/label';
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from '@/components/ui/form';
import { useToast } from '@/hooks/use-toast';
import { apiRequest } from '@/lib/queryClient';
import { type User } from '@/lib/types';
import { Settings as SettingsIcon, Lock, Bell } from 'lucide-react';

const passwordSchema = z.object({
  currentPassword: z.string().min(1, 'Wymagane'),
  newPassword: z.string().min(6, 'Minimum 6 znakow'),
  confirmPassword: z.string().min(1, 'Wymagane'),
}).refine((data) => data.newPassword === data.confirmPassword, {
  message: 'Hasla musza byc takie same',
  path: ['confirmPassword'],
});

type PasswordFormValues = z.infer<typeof passwordSchema>;

interface SettingsProps {
  currentUser: User;
}

export default function Settings({ currentUser }: SettingsProps) {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [notificationsEnabled, setNotificationsEnabled] = useState(currentUser.notificationsEnabled ?? true);

  const form = useForm<PasswordFormValues>({
    resolver: zodResolver(passwordSchema),
    defaultValues: {
      currentPassword: '',
      newPassword: '',
      confirmPassword: '',
    },
  });

  const changePasswordMutation = useMutation({
    mutationFn: async (data: { currentPassword: string; newPassword: string }) => {
      const res = await apiRequest('POST', '/api/user/change-password', data);
      return res.json();
    },
    onSuccess: () => {
      toast({
        title: 'Haslo zmienione',
        description: 'Twoje haslo zostalo pomyslnie zmienione.',
      });
      form.reset();
    },
    onError: (error: any) => {
      toast({
        title: 'Blad',
        description: error.message || 'Nie udalo sie zmienic hasla.',
        variant: 'destructive',
      });
    },
  });

  const updatePreferencesMutation = useMutation({
    mutationFn: async (data: { notificationsEnabled: boolean }) => {
      const res = await apiRequest('PATCH', '/api/user/preferences', data);
      return res.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/user'] });
      toast({
        title: 'Zapisano',
        description: 'Preferencje zostaly zaktualizowane.',
      });
    },
    onError: () => {
      toast({
        title: 'Blad',
        description: 'Nie udalo sie zapisac preferencji.',
        variant: 'destructive',
      });
    },
  });

  const onSubmitPassword = (data: PasswordFormValues) => {
    changePasswordMutation.mutate({
      currentPassword: data.currentPassword,
      newPassword: data.newPassword,
    });
  };

  const handleNotificationToggle = (checked: boolean) => {
    setNotificationsEnabled(checked);
    updatePreferencesMutation.mutate({ notificationsEnabled: checked });
  };

  return (
    <div className="p-6 max-w-2xl mx-auto space-y-6">
      <div className="flex items-center gap-3">
        <SettingsIcon className="h-6 w-6 text-muted-foreground" />
        <h1 className="text-2xl font-semibold" data-testid="text-settings-title">Ustawienia</h1>
      </div>

      <Card>
        <CardHeader>
          <div className="flex items-center gap-2">
            <Lock className="h-5 w-5 text-muted-foreground" />
            <CardTitle>Zmiana hasla</CardTitle>
          </div>
          <CardDescription>Zmien swoje haslo dostepu do systemu</CardDescription>
        </CardHeader>
        <CardContent>
          <Form {...form}>
            <form onSubmit={form.handleSubmit(onSubmitPassword)} className="space-y-4">
              <FormField
                control={form.control}
                name="currentPassword"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Obecne haslo</FormLabel>
                    <FormControl>
                      <Input
                        type="password"
                        placeholder="Wpisz obecne haslo"
                        data-testid="input-current-password"
                        {...field}
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />
              <FormField
                control={form.control}
                name="newPassword"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Nowe haslo</FormLabel>
                    <FormControl>
                      <Input
                        type="password"
                        placeholder="Wpisz nowe haslo"
                        data-testid="input-new-password"
                        {...field}
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />
              <FormField
                control={form.control}
                name="confirmPassword"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Potwierdz nowe haslo</FormLabel>
                    <FormControl>
                      <Input
                        type="password"
                        placeholder="Potwierdz nowe haslo"
                        data-testid="input-confirm-password"
                        {...field}
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />
              <Button
                type="submit"
                disabled={changePasswordMutation.isPending}
                data-testid="button-change-password"
              >
                {changePasswordMutation.isPending ? 'Zapisywanie...' : 'Zmien haslo'}
              </Button>
            </form>
          </Form>
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <div className="flex items-center gap-2">
            <Bell className="h-5 w-5 text-muted-foreground" />
            <CardTitle>Powiadomienia</CardTitle>
          </div>
          <CardDescription>Zarzadzaj swoimi preferencjami powiadomien</CardDescription>
        </CardHeader>
        <CardContent>
          <div className="flex items-center justify-between">
            <div className="space-y-0.5">
              <Label htmlFor="notifications" className="text-base">
                Powiadomienia o przypisanych leadach
              </Label>
              <p className="text-sm text-muted-foreground">
                Otrzymuj powiadomienia gdy zostanie Ci przypisany nowy lead
              </p>
            </div>
            <Switch
              id="notifications"
              checked={notificationsEnabled}
              onCheckedChange={handleNotificationToggle}
              disabled={updatePreferencesMutation.isPending}
              data-testid="switch-notifications"
            />
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

client/src/pages/QuickAssign.tsx.content:
import { useState } from 'react';
import { useQuery, useMutation } from '@tanstack/react-query';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Checkbox } from '@/components/ui/checkbox';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Skeleton } from '@/components/ui/skeleton';
import { useToast } from '@/hooks/use-toast';
import { apiRequest, queryClient } from '@/lib/queryClient';
import { type Lead, type User } from '@/lib/types';
import { UserPlus, Users, Mail, Phone, Loader2, CheckCircle } from 'lucide-react';

interface QuickAssignProps {
  currentUser: User;
}

export default function QuickAssign({ currentUser }: QuickAssignProps) {
  const [selectedLeads, setSelectedLeads] = useState<Set<string>>(new Set());
  const [bulkAssignee, setBulkAssignee] = useState<string>('');
  const [isBulkAssigning, setIsBulkAssigning] = useState(false);
  const { toast } = useToast();

  if (currentUser.role !== 'ADMIN') {
    return (
      <div className="p-8 text-center" data-testid="access-denied">
        <p className="text-lg font-medium">Brak dostepu</p>
        <p className="text-sm text-muted-foreground mt-1">
          Ta strona jest dostepna tylko dla administratorow
        </p>
      </div>
    );
  }

  const { data: leads = [], isLoading: leadsLoading } = useQuery<Lead[]>({
    queryKey: ['/api/leads'],
  });

  const { data: users = [], isLoading: usersLoading } = useQuery<User[]>({
    queryKey: ['/api/users'],
  });

  const salesReps = users.filter(u => u.role === 'SALES');
  const unassignedLeads = leads.filter(l => !l.assignedToId);

  const assignMutation = useMutation({
    mutationFn: async ({ leadId, assigneeId }: { leadId: string; assigneeId: string }) => {
      const response = await apiRequest('PATCH', `/api/leads/${leadId}`, {
        assignedToId: assigneeId,
      });
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/leads'] });
    },
  });

  const handleSingleAssign = async (leadId: string, assigneeId: string) => {
    try {
      await assignMutation.mutateAsync({ leadId, assigneeId });
      toast({
        title: 'Sukces',
        description: 'Lead zostal przypisany',
      });
    } catch (error) {
      toast({
        title: 'Blad',
        description: 'Nie udalo sie przypisac leada',
        variant: 'destructive',
      });
    }
  };

  const handleBulkAssign = async () => {
    if (!bulkAssignee || selectedLeads.size === 0) return;

    setIsBulkAssigning(true);
    const leadIds = Array.from(selectedLeads);

    const results = await Promise.allSettled(
      leadIds.map(async (leadId) => {
        const response = await apiRequest('PATCH', `/api/leads/${leadId}`, {
          assignedToId: bulkAssignee,
        });
        return response.json();
      })
    );

    const successCount = results.filter(r => r.status === 'fulfilled').length;
    const failCount = results.filter(r => r.status === 'rejected').length;

    queryClient.invalidateQueries({ queryKey: ['/api/leads'] });
    setSelectedLeads(new Set());
    setBulkAssignee('');
    setIsBulkAssigning(false);

    toast({
      title: 'Zakonczone',
      description: `Przypisano ${successCount} leadow${failCount > 0 ? `, ${failCount} nie udalo sie` : ''}`,
    });
  };

  const toggleLeadSelection = (leadId: string) => {
    setSelectedLeads(prev => {
      const newSet = new Set(prev);
      if (newSet.has(leadId)) {
        newSet.delete(leadId);
      } else {
        newSet.add(leadId);
      }
      return newSet;
    });
  };

  const toggleSelectAll = () => {
    if (selectedLeads.size === unassignedLeads.length) {
      setSelectedLeads(new Set());
    } else {
      setSelectedLeads(new Set(unassignedLeads.map(l => l.id)));
    }
  };

  if (leadsLoading || usersLoading) {
    return (
      <div className="p-8 space-y-6" data-testid="quick-assign-loading">
        <Skeleton className="h-8 w-64" />
        <Skeleton className="h-64 w-full" />
      </div>
    );
  }

  return (
    <div className="p-8 space-y-6" data-testid="quick-assign-page">
      <div className="flex items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-semibold">Szybkie przypisanie</h1>
          <p className="text-sm text-muted-foreground mt-1">
            Przypisz nieprzypisane leady do handlowcow
          </p>
        </div>
        <Badge variant="secondary" className="text-base px-3 py-1">
          {unassignedLeads.length} nieprzypisanych
        </Badge>
      </div>

      {selectedLeads.size > 0 && (
        <Card className="border-primary/50 bg-primary/5">
          <CardContent className="p-4">
            <div className="flex items-center gap-4 flex-wrap">
              <span className="text-sm font-medium">
                Zaznaczono: {selectedLeads.size} leadow
              </span>
              <Select value={bulkAssignee} onValueChange={setBulkAssignee}>
                <SelectTrigger className="w-[200px]" data-testid="select-bulk-assignee">
                  <SelectValue placeholder="Wybierz handlowca" />
                </SelectTrigger>
                <SelectContent>
                  {salesReps.map(rep => (
                    <SelectItem key={rep.id} value={rep.id}>
                      {rep.name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
              <Button
                onClick={handleBulkAssign}
                disabled={!bulkAssignee || isBulkAssigning}
                data-testid="button-bulk-assign"
              >
                {isBulkAssigning ? (
                  <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                ) : (
                  <UserPlus className="w-4 h-4 mr-2" />
                )}
                Przypisz wszystkie
              </Button>
            </div>
          </CardContent>
        </Card>
      )}

      <Card>
        <CardHeader className="pb-3">
          <div className="flex items-center justify-between gap-4">
            <CardTitle className="text-lg font-semibold flex items-center gap-2">
              <Users className="w-5 h-5 text-muted-foreground" />
              Nieprzypisane leady
            </CardTitle>
            {unassignedLeads.length > 0 && (
              <Button variant="outline" size="sm" onClick={toggleSelectAll} data-testid="button-select-all">
                {selectedLeads.size === unassignedLeads.length ? 'Odznacz wszystko' : 'Zaznacz wszystko'}
              </Button>
            )}
          </div>
        </CardHeader>
        <CardContent>
          {unassignedLeads.length === 0 ? (
            <div className="py-12 text-center" data-testid="empty-state">
              <CheckCircle className="w-12 h-12 mx-auto mb-4 text-green-500" />
              <p className="text-lg font-medium">Wszystkie leady sa przypisane</p>
              <p className="text-sm text-muted-foreground mt-1">
                Nie ma nieprzypisanych leadow do wyswietlenia
              </p>
            </div>
          ) : (
            <div className="space-y-2">
              {unassignedLeads.map(lead => (
                <div
                  key={lead.id}
                  className="flex items-center gap-4 p-4 rounded-lg border hover-elevate"
                  data-testid={`lead-row-${lead.id}`}
                >
                  <Checkbox
                    checked={selectedLeads.has(lead.id)}
                    onCheckedChange={() => toggleLeadSelection(lead.id)}
                    data-testid={`checkbox-lead-${lead.id}`}
                  />
                  <div className="flex-1 min-w-0">
                    <p className="font-medium truncate">
                      {lead.firstName} {lead.lastName}
                    </p>
                    <div className="flex items-center gap-4 mt-1 text-sm text-muted-foreground">
                      <span className="flex items-center gap-1 truncate">
                        <Mail className="w-3 h-3 shrink-0" />
                        {lead.email}
                      </span>
                      {lead.phone && (
                        <span className="flex items-center gap-1">
                          <Phone className="w-3 h-3 shrink-0" />
                          {lead.phone}
                        </span>
                      )}
                    </div>
                  </div>
                  <Badge variant="secondary">{lead.source || 'Brak zrodla'}</Badge>
                  <Select
                    onValueChange={(value) => handleSingleAssign(lead.id, value)}
                  >
                    <SelectTrigger className="w-[180px]" data-testid={`select-assign-${lead.id}`}>
                      <SelectValue placeholder="Przypisz do..." />
                    </SelectTrigger>
                    <SelectContent>
                      {salesReps.map(rep => (
                        <SelectItem key={rep.id} value={rep.id}>
                          {rep.name}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}
